const dayUtils: DatePickerUtils = {
  getItemKey: (rowIndex, rowItemIndex) => `${rowIndex}:${rowItemIndex}`,
  isSameItem: (date1: Date, date2: Date) => isSameDay(date1, date2),
  isSamePage: (date1: Date, date2: Date) => isSameMonth(date1, date2),
  checkIfCurrentDay: date => isToday(date),
  checkIfCurrentMonth: () => false,
  checkIfCurrent: date => isToday(date),
  getPageName: () => 'month',
};

const monthUtils: DatePickerUtils = {
  getItemKey: (rowIndex, rowItemIndex) => `Month ${rowIndex * 3 + rowItemIndex + 1}`,
  isSameItem: (date1: Date, date2: Date) => isSameMonth(date1, date2),
  isSamePage: (date1: Date, date2: Date) => isSameYear(date1, date2),
  checkIfCurrentDay: () => false,
  checkIfCurrentMonth: date => isThisMonth(date),
  checkIfCurrent: date => isThisMonth(date),
  getPageName: () => 'year',
};

const announceEnd = (endDate: Date) => {
  return `${i18n('i18nStrings.endDateLabel', i18nStrings?.endDateLabel)}, ${getDateLabel(normalizedLocale, endDate)}${
    hideTime
      ? ''
      : `, ${i18n('i18nStrings.endTimeLabel', i18nStrings?.endTimeLabel)}, ${renderTimeLabel(
          normalizedLocale,
          endDate,
          timeInputFormat
        )}`
  }. `;
};

const announceStart = (startDate: Date) => {
  return `${i18n('i18nStrings.startDateLabel', i18nStrings?.startDateLabel)}, ${getDateLabel(normalizedLocale, startDate)}${
    hideTime
      ? ''
      : `, ${i18n('i18nStrings.startTimeLabel', i18nStrings?.startTimeLabel)}, ${renderTimeLabel(
          normalizedLocale,
          startDate,
          timeInputFormat
        )}`
  }. `;
};

export const defaultDetails =
  (i18n: ComponentFormatFunction<'pie-chart'>, i18nStrings: PieChartProps.I18nStrings) =>
  (datum: PieChartProps.Datum, dataSum: number) => [
    { key: i18n('i18nStrings.detailsValue', i18nStrings.detailsValue) || '', value: datum.value },
    {
      key: i18n('i18nStrings.detailsPercentage', i18nStrings.detailsPercentage) || '',
      value: `${((datum.value * 100) / dataSum).toFixed(0)}%`,
    },
  ];

return (
  <InternalSegmentedControl
    className={testutilStyles['mode-switch']}
    selectedId={mode}
    label={i18nStrings?.modeSelectionLabel}
    options={[
      { id: 'relative', text: i18n('i18nStrings.relativeModeTitle', i18nStrings?.relativeModeTitle) },
      { id: 'absolute', text: i18n('i18nStrings.absoluteModeTitle', i18nStrings?.absoluteModeTitle) },
    ]}
    onChange={e => onChange(e.detail.selectedId as 'absolute' | 'relative')}
  />
);

const menuDropdownStatusResult = useDropdownStatus({
  ...(activeMenu ?? {}),
  isEmpty: !menuItemsState || menuItemsState.items.length === 0,
  recoveryText: i18nStrings?.menuRecoveryText,
  errorIconAriaLabel: i18nStrings?.menuErrorIconAriaLabel,
  loadingText: i18nStrings?.menuLoadingText,
  finishedText: i18nStrings?.menuFinishedText,
  errorText: i18nStrings?.menuErrorText,
  onRecoveryClick: () => {
    if (menuLoadMoreHandlers) {
      menuLoadMoreHandlers.fireLoadMoreOnRecoveryClick();
    }
    editableElementRef.current?.focus();
  },
  hasRecoveryCallback: Boolean(onMenuLoadItems),
});

const elementIds = React.useMemo(
  () => ({
    labelId: labelId ?? `${baseId}-label`,
    menuId: menuId ?? `${baseId}-menu`,
    getItemId: getItemId ?? (index => `${baseId}-item-${index}`),
    toggleButtonId: toggleButtonId ?? `${baseId}-toggle-button`,
    inputId: inputId ?? `${baseId}-input`,
  }),
  [getItemId, inputId, labelId, menuId, toggleButtonId, baseId],
)

if (a === Kind.Error || b === Kind.Error) {
  return Kind.Error;
} else if (a === Kind.KnownHook || b === Kind.KnownHook) {
  return Kind.KnownHook;
} else if (a === Kind.PotentialHook || b === Kind.PotentialHook) {
  return Kind.PotentialHook;
} else if (a === Kind.Global || b === Kind.Global) {
  return Kind.Global;
} else {
  return Kind.Local;
}

return (
  <>
    {withGradient ? (
      <linearGradient id={id} x1="0" y1="0" x2="0" y2="1">
        <stop offset="0%" stopColor={color} stopOpacity={fillOpacity} />
        <stop offset="100%" stopColor={color} stopOpacity={0.01} />
      </linearGradient>
    ) : (
      <linearGradient id={id} x1="0" y1="0" x2="0" y2="1">
        <stop stopColor={color} stopOpacity={fillOpacity ?? 0.2} />
      </linearGradient>
    )}
  </>
);

return (
  <div style={{ padding: 40 }}>
    <div>1 column</div>
    <DecadeLevelGroup decade="2022-04-11" mb={50} mt="xs" />

    <div>2 columns</div>
    <DecadeLevelGroup numberOfColumns={2} decade="2022-04-11" mb={50} mt="xs" />

    <div>3 columns</div>
    <DecadeLevelGroup numberOfColumns={3} decade="2022-04-11" mb={50} mt="xs" />
  </div>
);

return (
  <div style={{ padding: 40, width: 320 }}>
    <MonthsList year="2022-01-01" getMonthControlProps={() => ({ inRange: true })} />
    <MonthsList
      year="2022-01-01"
      getMonthControlProps={() => ({ firstInRange: true, selected: true })}
    />
    <MonthsList
      year="2022-01-01"
      getMonthControlProps={() => ({ lastInRange: true, selected: true })}
    />
  </div>
);

return (
  <div style={{ padding: 40, width: 320 }}>
    <YearsList decade="2022-02-01" getYearControlProps={() => ({ inRange: true })} />
    <YearsList
      decade="2022-02-01"
      getYearControlProps={() => ({ firstInRange: true, selected: true })}
    />
    <YearsList
      decade="2022-02-01"
      getYearControlProps={() => ({ lastInRange: true, selected: true })}
    />
  </div>
);

export const FigmaIcon = createSvgIcon(
  <g fillRule="nonzero" fill="none">
    <path d="M8 24a4 4 0 004-4v-4H8a4 4 0 000 8z" fill="#0ACF83" />
    <path d="M4 12a4 4 0 014-4h4v8H8a4 4 0 01-4-4z" fill="#A259FF" />
    <path d="M4 4a4 4 0 014-4h4v8H8a4 4 0 01-4-4z" fill="#F24E1E" />
    <path d="M12 0h4a4 4 0 010 8h-4V0z" fill="#FF7262" />
    <path d="M20 12a4 4 0 11-8 0 4 4 0 018 0z" fill="#1ABCFE" />
  </g>,
  'Figma',
);

return (
  <React.Fragment>
    {yTicks.map(({ value, offset }) =>
      !instance.isYInside(offset) ? null : (
        <GridLine
          key={`horizontal-${value?.getTime?.() ?? value}`}
          y1={offset}
          y2={offset}
          x1={start}
          x2={end}
          className={classes.horizontalLine}
        />
      ),
    )}
  </React.Fragment>
);

return (
  <React.Fragment>
    {xTicks.map(({ value, offset }) =>
      !instance.isXInside(offset) ? null : (
        <GridLine
          key={`vertical-${value?.getTime?.() ?? value}`}
          y1={start}
          y2={end}
          x1={offset}
          x2={offset}
          className={classes.verticalLine}
        />
      ),
    )}
  </React.Fragment>
);

if (type === 'line') {
  const lineAngle = isOrdinalScale(rotationScale) ? angle + rotationScale.bandwidth() / 2 : angle;
  const [x1, y1] = polarToSvg(cx, cy, innerRadius, lineAngle);
  const [x2, y2] = polarToSvg(cx, cy, outerRadius, lineAngle);

  return (
    <ChartsRadialAxisHighlightPath
      d={`M ${x1} ${y1} L ${x2} ${y2}`}
      className={classes.root}
      ownerState={{ axisHighlight: 'line' }}
    />
  );
}

if (dateRange1 == null && dateRange2 == null) {
    return true;
} else if (dateRange1 == null || dateRange2 == null) {
    return false;
} else {
    const [start1, end1] = dateRange1;
    const [start2, end2] = dateRange2;
    const areStartsEqual =
        (start1 == null && start2 == null) || (start1 != null && start2 != null && isSameDay(start1, start2));
    const areEndsEqual = (end1 == null && end2 == null) || (end1 != null && end2 != null && isSameDay(end1, end2));
    return areStartsEqual && areEndsEqual;
}
